import React from 'react';
import { Alert } from 'react-native';

const API_URL = 'https://api.example.com';
const LOCAL_DEVICE_URL = 'http://192.168.x.x';

const headers = {
  'Content-Type': 'application/json',
  Accept: 'application/json',
};

const fetchFromAPI = async (endpoint, method = 'GET', body) => {
  try {
    const response = await fetch(`${API_URL}${endpoint}`, {
      method,
      headers,
      body: JSON.stringify(body),
    });

    if (!response.ok) {
      throw new Error(`Error: ${response.statusText}`);
    }
    
    return await response.json();
  } catch (error) {
    Alert.alert('API Error', error.message);
    throw error;
  }
};

const fetchFromLocalDevice = async (endpoint, method = 'GET', body) => {
  try {
    const response = await fetch(`${LOCAL_DEVICE_URL}${endpoint}`, {
      method,
      headers,
      body: JSON.stringify(body),
    });

    if (!response.ok) {
      throw new Error(`Error: ${response.statusText}`);
    }

    return await response.json();
  } catch (error) {
    Alert.alert('Local Device Error', error.message);
    throw error;
  }
};

export const NetworkingModule = {
  fetchFromAPI,
  fetchFromLocalDevice,
};